import json
import os
import subprocess
import tempfile
import pytest

AC_UID = "ac8_baseline_import_populates_21_agents"
AC_TYPE = "data"

CANONICAL_AGENTS = {
    "ba", "dev", "qa",
    "ui-specialist", "architect", "product-owner", "user", "pm",
    "changelog-analyst", "push-analyst", "merge-analyst", "pull-analyst",
    "cleanliness-inspector", "style-inspector", "prompt-inspector",
    "rule-inspector", "git-edge-case-analyst", "cleaner",
    "test-validator", "test-executor", "spec",
}


def test_AC8():
    """
    GIVEN: logs/lifecycle.jsonl is empty (zero bytes, as currently committed)
    WHEN:  bash scripts/lifecycle-baseline-import.sh is invoked once
    THEN:  logs/lifecycle.jsonl contains exactly 21 lines (one per canonical agent), each line parses as valid JSON with event=score_baseline_import and agent matching a canonical agent name
    """
    repo = "/dev/shm/dev-workspace/dot-claude"
    fd_lc, tmp_lifecycle = tempfile.mkstemp(suffix=".jsonl", prefix="test-ac8-lc-")
    fd_sc, tmp_scores = tempfile.mkstemp(suffix=".json", prefix="test-ac8-sc-")
    try:
        os.close(fd_lc)  # empty lifecycle
        data = {"global": {"agents": {ag: {"score": 55, "rank": "Skilled Craftsman", "history": []} for ag in CANONICAL_AGENTS}}}
        with os.fdopen(fd_sc, "w") as f:
            json.dump(data, f)

        result = subprocess.run(
            ["bash", "scripts/lifecycle-baseline-import.sh",
             "--lifecycle-file", tmp_lifecycle, "--scores-file", tmp_scores],
            capture_output=True, text=True, cwd=repo,
        )
        assert result.returncode == 0, f"lifecycle-baseline-import.sh failed: {result.stderr}"

        with open(tmp_lifecycle) as f:
            lines = [l.rstrip("\n") for l in f if l.strip()]

        assert len(lines) == 21, f"Expected 21 lines (one per canonical agent), got {len(lines)}"

        for i, raw in enumerate(lines):
            entry = json.loads(raw)
            assert entry.get("event") == "score_baseline_import", (
                f"Line {i+1}: expected event=score_baseline_import, got {entry.get('event')}"
            )
            assert entry.get("agent") in CANONICAL_AGENTS, (
                f"Line {i+1}: agent '{entry.get('agent')}' not in canonical agents set"
            )
    finally:
        for p in (tmp_lifecycle, tmp_scores):
            try:
                os.unlink(p)
            except OSError:
                pass
